#include <bits/stdc++.h>
using namespace std;

int main() {
    ios_base::sync_with_stdio(false); cin.tie(NULL);
    int n; cin >> n;
    vector<int> childCnt(n + 1, 0);
    for (int i = 1; i <= n; i++) {
        int p; cin >> p;
        if (p >= 1 && p <= n) childCnt[p]++;
    }
    int leaves = 0;
    for (int i = 1; i <= n; i++) if (childCnt[i] == 0) leaves++;
    cout << leaves << "\n";
    return 0;
}
